<script setup lang="ts">
import { ref, toRef, watch } from 'vue'
import { PhWarning } from '@phosphor-icons/vue'
import { useModalLifecycle } from './useModalLifecycle'
const props=defineProps<{ open:boolean; title:string; message:string; confirmLabel?:string; promptLabel?:string; destructive?:boolean }>(); const emit=defineEmits<{ cancel:[]; confirm:[value?:string] }>(); const panel=ref<HTMLElement|null>(null); const value=ref(''); watch(()=>props.open,open=>{if(open)value.value='' }); useModalLifecycle(toRef(props,'open'),panel,()=>emit('cancel'))
</script>
<template><Teleport to="body"><div v-if="open" class="mobile-dialog-backdrop"><section ref="panel" class="mobile-dialog" role="alertdialog" aria-modal="true" aria-labelledby="confirm-title" aria-describedby="confirm-message"><PhWarning :size="30" weight="duotone" aria-hidden="true"/><h2 id="confirm-title">{{title}}</h2><p id="confirm-message">{{message}}</p><label v-if="promptLabel">{{promptLabel}}<textarea v-model="value" maxlength="1000"/></label><div><button type="button" data-autofocus @click="$emit('cancel')">Keep it</button><button type="button" :class="{danger:destructive}" @click="$emit('confirm',promptLabel?value:undefined)">{{confirmLabel??'Confirm'}}</button></div></section></div></Teleport></template>
